$base = "$env:USERPROFILE\Desktop\AssetManagement"
$enc  = [System.Text.Encoding]::UTF8
Write-Host "Stage 8: Multi-round rejections + Manual Create/Edit" -ForegroundColor Cyan

$p = "$base\AssetManagement.Application\Services\WorkflowService.cs"
$d = Split-Path $p
if (-not (Test-Path $d)) { New-Item -ItemType Directory -Path $d -Force | Out-Null }
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes($p, $b)
Write-Host "  OK: WorkflowService.cs" -ForegroundColor Green

$p = "$base\AssetManagement.Web\Controllers\FinanceController.cs"
$d = Split-Path $p
if (-not (Test-Path $d)) { New-Item -ItemType Directory -Path $d -Force | Out-Null }
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes($p, $b)
Write-Host "  OK: FinanceController.cs" -ForegroundColor Green

$p = "$base\AssetManagement.Application\ViewModels\AssetFormViewModel.cs"
$d = Split-Path $p
if (-not (Test-Path $d)) { New-Item -ItemType Directory -Path $d -Force | Out-Null }
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes($p, $b)
Write-Host "  OK: AssetFormViewModel.cs" -ForegroundColor Green

$p = "$base\AssetManagement.Web\Views\Asset\Create.cshtml"
$d = Split-Path $p
if (-not (Test-Path $d)) { New-Item -ItemType Directory -Path $d -Force | Out-Null }
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes($p, $b)
Write-Host "  OK: Create.cshtml" -ForegroundColor Green

$p = "$base\AssetManagement.Web\Views\Asset\Edit.cshtml"
$d = Split-Path $p
if (-not (Test-Path $d)) { New-Item -ItemType Directory -Path $d -Force | Out-Null }
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes($p, $b)
Write-Host "  OK: Edit.cshtml" -ForegroundColor Green

# Insert Create/Edit actions into AssetController.cs
$acp = "$base\AssetManagement.Web\Controllers\AssetController.cs"
$ac  = [System.IO.File]::ReadAllText($acp, $enc)
$actions = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
if (-not $ac.Contains("public IActionResult Create()")) {
    $lastBrace = $ac.LastIndexOf("}")
    $secondLastBrace = $ac.LastIndexOf("}", $lastBrace - 1)
    $ac = $ac.Substring(0, $secondLastBrace) + $actions + "`r`n    }`r`n}`r`n"
    [System.IO.File]::WriteAllText($acp, $ac, $enc)
    Write-Host "  OK: Create/Edit actions added to AssetController" -ForegroundColor Green
} else {
    Write-Host "  INFO: Create/Edit actions already exist" -ForegroundColor Yellow
}

# Add "Add Asset" button to Index header
$ip = "$base\AssetManagement.Web\Views\Asset\Index.cshtml"
$ic = [System.IO.File]::ReadAllText($ip, $enc)
$oldBtn = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
$newBtn = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
if ($ic.Contains($oldBtn)) {
    $ic = $ic.Replace($oldBtn, $newBtn)
    [System.IO.File]::WriteAllText($ip, $ic, $enc)
    Write-Host "  OK: Add Asset button added to Index" -ForegroundColor Green
} else {
    Write-Host "  WARN: Index header pattern not matched - add manually" -ForegroundColor Yellow
}

# Add Edit button to Details toolbar
$dp = "$base\AssetManagement.Web\Views\Asset\Details.cshtml"
$dc = [System.IO.File]::ReadAllText($dp, $enc)
$oldDBtn = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
$newDBtn = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
if ($dc.Contains($oldDBtn)) {
    $dc = $dc.Replace($oldDBtn, $newDBtn)
    [System.IO.File]::WriteAllText($dp, $dc, $enc)
    Write-Host "  OK: Edit button added to Details" -ForegroundColor Green
} else {
    Write-Host "  WARN: Details toolbar pattern not matched - add manually" -ForegroundColor Yellow
}

cd $base
dotnet build 2>&1 | Select-Object -Last 4
if ($LASTEXITCODE -eq 0) { Write-Host "Stage 8 build OK!" -ForegroundColor Green }